import{_ as s,n as e,p as i,Y as a}from"./chunks/framework.KP8KjELV.js";const f=JSON.parse('{"title":"sftp 命令","description":"","frontmatter":{},"headers":[],"relativePath":"Stack/Linux/SSH/Tutorial/sftp.md","filePath":"Stack/Linux/SSH/Tutorial/sftp.md","lastUpdated":1703840066000}'),t={name:"Stack/Linux/SSH/Tutorial/sftp.md"},l=a(`<h1 id="sftp-命令" tabindex="-1">sftp 命令 <a class="header-anchor" href="#sftp-命令" aria-label="Permalink to &quot;sftp 命令&quot;">​</a></h1><p><code>sftp</code>是 SSH 提供的一个客户端应用程序，主要用来安全地访问 FTP。因为 FTP 是不加密协议，很不安全，<code>sftp</code>就相当于将 FTP 放入了 SSH。</p><p>下面的命令连接 FTP 主机。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sftp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> username@hostname</span></span></code></pre></div><p>执行上面的命令，会要求输入 FTP 的密码。密码验证成功以后，就会出现 FTP 的提示符<code>sftp&gt; </code>，下面是一个例子。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sftp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> USER@penguin.example.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">USER@penguin.example.com</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&#39;s password:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Connected to penguin.example.com.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sftp&gt;</span></span></code></pre></div><p>FTP 的提示符下面，就可以输入各种 FTP 命令了，这部分完全跟传统的 FTP 用法完全一样。</p><ul><li><code>ls [directory]</code>：列出一个远程目录的内容。如果没有指定目标目录，则默认列出当前目录。</li><li><code>cd directory</code>：从当前目录改到指定目录。</li><li><code>mkdir directory</code>：创建一个远程目录。</li><li><code>rmdir path</code>：删除一个远程目录。</li><li><code>put localfile [remotefile]</code>：本地文件传输到远程主机。</li><li><code>get remotefile [localfile]</code>：远程文件传输到本地。</li><li><code>help</code>：显示帮助信息。</li><li><code>bye</code>：退出 sftp。</li><li><code>quit</code>：退出 sftp。</li><li><code>exit</code>：退出 sftp。</li></ul>`,8),p=[l];function n(o,c,d,h,r,k){return e(),i("div",null,p)}const u=s(t,[["render",n]]);export{f as __pageData,u as default};
